// Build a structured prompt for LLM triage
// Injects all relevant alert context so the model has full signal

const alert = $input.first().json;

const systemPrompt = `You are a senior cloud security engineer with expertise in AWS, Kubernetes, and enterprise IAM. 
You are performing alert triage for a security operations team.

Your job is to evaluate each cloud security alert and return a structured JSON triage decision.

Evaluate the alert on these four dimensions:
1. Blast radius — how many systems, users, or data assets could be affected if this is a real incident
2. Resource sensitivity — production vs dev/staging, data classification, public-facing vs internal
3. Attack pattern — does this match a known threat (MITRE ATT&CK TTP, common misconfiguration, known malware)
4. Exploitability — how easy is this to exploit right now (no additional steps = higher score)

Return ONLY valid JSON. No preamble, no explanation outside the JSON block.

JSON schema:
{
  "risk_score": <integer 1-10>,
  "triage_decision": <"true_positive" | "false_positive" | "needs_investigation">,
  "triage_rationale": <2-3 sentences explaining the score and recommended immediate action>
}

Scoring guide:
- 9-10: Active threat or critical exposure requiring immediate response (< 1 hour)
- 7-8: High confidence finding requiring same-day response
- 5-6: Medium confidence, investigate within 48 hours
- 3-4: Low confidence or low impact, schedule for review
- 1-2: Likely false positive, verify and close`;

const userPrompt = `Triage the following cloud security alert:

Source: ${alert.source}
Severity (vendor-assigned): ${alert.severity}
Title: ${alert.title}
Description: ${alert.description}
Resource ID: ${alert.resource_id}
Resource Type: ${alert.resource_type}
Cloud Account: ${alert.cloud_account}
Region: ${alert.region}
Environment: ${alert.env_tag || 'unknown'}
Owner team: ${alert.owner_tag || 'untagged'}
Original timestamp: ${alert.timestamp}`;

return [{
  json: {
    ...alert,
    _system_prompt: systemPrompt,
    _user_prompt: userPrompt
  }
}];

// Parse the LLM response and merge back with the original alert
// Handle malformed JSON gracefully — don't let a bad LLM response kill the flow

const alert = $input.first().json;
let triageResult = {};

try {
  const rawContent = alert.message?.content || alert.choices?.[0]?.message?.content || '{}';
  const cleaned = rawContent.replace(/```json|```/g, '').trim();
  triageResult = JSON.parse(cleaned);

  // Validate fields
  if (typeof triageResult.risk_score !== 'number') {
    triageResult.risk_score = 5; // safe default
  }
  triageResult.risk_score = Math.min(10, Math.max(1, Math.round(triageResult.risk_score)));

  const validDecisions = ['true_positive', 'false_positive', 'needs_investigation'];
  if (!validDecisions.includes(triageResult.triage_decision)) {
    triageResult.triage_decision = 'needs_investigation';
  }

  if (!triageResult.triage_rationale) {
    triageResult.triage_rationale = 'Automated triage — manual review recommended.';
  }

} catch (e) {
  // Fallback if LLM returns unparseable content
  triageResult = {
    risk_score: 5,
    triage_decision: 'needs_investigation',
    triage_rationale: `Automated triage failed to parse LLM response. Manual review required. Parse error: ${e.message}`
  };
}

// Clean up internal prompt fields before writing back
const { _system_prompt, _user_prompt, ...cleanAlert } = alert;

return [{
  json: {
    ...cleanAlert,
    risk_score:        triageResult.risk_score,
    triage_decision:   triageResult.triage_decision,
    triage_rationale:  triageResult.triage_rationale,
    scored_at:         new Date().toISOString()
  }
}];

